/**
 * backfillKinyarwanda.js
 *
 * Fills in missing Kinyarwanda fields for all LegalContent documents:
 *
 *  1. reportingSteps[*].description.rw  — static translations (all articles
 *     have the same generic steps, so no API needed)
 *
 *  2. simplifiedExplanation.rw  — generated by Groq AI per article
 *     (rate-limited to 30 req/min; progress saved to backfill-checkpoint.json
 *      so the script can be safely interrupted and resumed)
 *
 * Run from project root:
 *   node backend/data/backfillKinyarwanda.js
 *
 * To resume after interruption, just run it again — checkpoint is automatic.
 */

import 'dotenv/config'
import { readFileSync, writeFileSync, existsSync } from 'fs'
import { fileURLToPath } from 'url'
import { dirname, resolve } from 'path'
import mongoose from 'mongoose'
import Groq from 'groq-sdk'
import LegalContent from '../src/models/LegalContent.js'

const __dirname = dirname(fileURLToPath(import.meta.url))
const CHECKPOINT_FILE = resolve(__dirname, 'backfill-checkpoint.json')

const GROQ_MODEL   = 'llama-3.3-70b-versatile'
const DELAY_MS     = 2200   // ~27 req/min — safely under the 30/min limit
const BATCH_DB     = 20     // save to DB every N articles

// ─── Static Kinyarwanda for the generic reporting steps ───────────────────────
// parsedLaws.json has the same 4–5 generic steps for every article.
// These are accurate Kinyarwanda translations of those templates.
const STEP_TRANSLATIONS = {
  // Fraud steps
  'Collect all evidence: messages, receipts, contracts, screenshots.':
    'Bika ibimenyetso byose: ubutumwa, ibyemeza, amasezerano, amashusho ya screen.',
  'Report to Rwanda National Police or Rwanda Investigation Bureau (RIB).':
    'Tanga raporo kuri Polisi y\'Igihugu cy\'u Rwanda cyangwa Rwanda Investigation Bureau (RIB).',
  'Provide a detailed written account of the fraud.':
    'Tanga ibisobanuro byanditse birambuye ku buriganya.',
  'Bring all documents and evidence when you report.':
    'Zana impapuro zose n\'ibimenyetso igihe utanga raporo.',

  // Default/other steps
  'Report the incident to the nearest police station.':
    'Tanga raporo ku kigo cy\'ubutabera cya Polisi y\'Igihugu cy\'u Rwanda hafi yawe.',
  'Provide a full account of what happened.':
    'Tanga ibisobanuro byuzuye ku byabaye.',
  'Bring any available evidence or witnesses.':
    'Zana ibimenyetso bihari cyangwa abitangarira.',
  'Request a Police Abstract (official report).':
    'Saba inyandiko yemewe ya Polisi (raporo igaragaza ikirego).',
  'Seek legal aid at the nearest Legal Aid Forum Rwanda office.':
    'Shaka ubufasha bw\'amategeko ku biro bya Legal Aid Forum Rwanda bya hafi.',

  // Assault/GBV steps
  'Go to the nearest hospital for medical documentation of injuries.':
    'Jya ku bitaro bya hafi kugirango ubuvuzi bugaragaze inshike zawe.',
  'Preserve all physical evidence before washing or cleaning.':
    'Rinda ibimenyetso byose ku mubiri mbere yo kwoza cyangwa gusukura.',
  'Identify the perpetrator to police if possible.':
    'Sobanura uwagikoze kuri polisi bishoboka.',
  'Request victim support services at the station.':
    'Saba serivisi zo gufasha inzirakarengane mu kigo.',

  // Murder steps
  'Call emergency services (112) immediately.':
    'Téléfonera serivisi z\'ihutirwa (112) ako kanya.',
  'Do not disturb the crime scene.':
    'Ntugire icyo uhindura ahantu ikirego cyabereye.',
  'Provide witness information to police.':
    'Tanga amakuru y\'abitangarira kuri polisi.',
  'Cooperate fully with the investigation.':
    'Korana na polisi mu gukora isesengura ryuzuye.',
}

/**
 * Translate a single reporting step description to Kinyarwanda.
 * Uses static lookup first; falls back to a short generic translation.
 */
function translateStep(enText) {
  if (!enText) return ''
  // Exact match
  if (STEP_TRANSLATIONS[enText]) return STEP_TRANSLATIONS[enText]
  // Partial match
  const key = Object.keys(STEP_TRANSLATIONS).find(k =>
    enText.toLowerCase().includes(k.toLowerCase().substring(0, 30))
  )
  if (key) return STEP_TRANSLATIONS[key]
  // Generic fallback
  return 'Kora ibi wandikiwe hejuru ukoresheje ururimi rw\'Ikinyarwanda.'
}

// ─── Groq client ──────────────────────────────────────────────────────────────
const groq = new Groq({ apiKey: process.env.GROQ_API_KEY })

async function generateSimplifiedRw(article) {
  const crimeType  = article.crimeType
  const articleNum = article.articleNumber
  const enText     = (article.originalText?.en || '').substring(0, 600)
  const rwText     = (article.originalText?.rw || '').substring(0, 600)

  const prompt = rwText.length > 30
    ? `Sobanura ingingo ya ${articleNum} y'Itegeko Ngenga rya 2018 iry'u Rwanda mu magambo yoroheje mu Kinyarwanda. Ingingo ivuga:\n\n"${rwText}"\n\nSubiza mu magambo yoroheje y'Ikinyarwanda, interuro 2 gusa.`
    : `Translate and simplify this Rwanda Penal Code article into plain Kinyarwanda (2 sentences only):\n\n${articleNum} — ${crimeType}: "${enText}"`

  const resp = await groq.chat.completions.create({
    model: GROQ_MODEL,
    messages: [
      {
        role: 'system',
        content: 'You are a Rwandan legal translator. Write ONLY in Kinyarwanda. Maximum 2 sentences. Plain language. No French. No English.'
      },
      { role: 'user', content: prompt }
    ],
    temperature: 0.1,
    max_tokens: 150
  })

  return resp.choices[0]?.message?.content?.trim() || ''
}

// ─── Checkpoint helpers ────────────────────────────────────────────────────────
function loadCheckpoint() {
  if (existsSync(CHECKPOINT_FILE)) {
    return JSON.parse(readFileSync(CHECKPOINT_FILE, 'utf8'))
  }
  return { completed: [] }
}

function saveCheckpoint(completed) {
  writeFileSync(CHECKPOINT_FILE, JSON.stringify({ completed }, null, 2))
}

// ─── Main ─────────────────────────────────────────────────────────────────────
async function backfill() {
  await mongoose.connect(process.env.MONGODB_URI)
  console.log('✅  Connected to MongoDB')

  const checkpoint = loadCheckpoint()
  const done = new Set(checkpoint.completed)
  console.log(`📌  Checkpoint: ${done.size} articles already completed`)

  // ── Step 1: Fill reporting steps (no API, instant) ────────────────────────
  console.log('\n⚙️   Step 1: Backfilling reportingSteps.description.rw (static translations)...')

  const allDocs = await LegalContent.find({}).lean()
  const stepOps = []

  for (const doc of allDocs) {
    const updatedSteps = (doc.reportingSteps || []).map(step => ({
      ...step,
      description: {
        en: step.description?.en || '',
        rw: step.description?.rw || translateStep(step.description?.en || '')
      }
    }))
    stepOps.push({
      updateOne: {
        filter: { _id: doc._id },
        update: { $set: { reportingSteps: updatedSteps } }
      }
    })
  }

  if (stepOps.length) {
    await LegalContent.bulkWrite(stepOps, { ordered: false })
    console.log(`   ✅  Updated reporting steps for ${stepOps.length} articles`)
  }

  // ── Step 2: Fill simplifiedExplanation.rw via Groq ────────────────────────
  const needsRw = allDocs.filter(d =>
    !done.has(d._id.toString()) &&
    (!d.simplifiedExplanation?.rw || d.simplifiedExplanation.rw.trim() === '')
  )

  console.log(`\n⚙️   Step 2: Generating simplifiedExplanation.rw via Groq for ${needsRw.length} articles...`)
  console.log(`    (Rate limited to ~27 req/min — estimated time: ${Math.ceil(needsRw.length * DELAY_MS / 60000)} min)\n`)

  if (needsRw.length === 0) {
    console.log('   ✅  All articles already have Kinyarwanda simplified explanations.')
  }

  let success = 0
  let failed  = 0
  const pendingSave = []

  for (let i = 0; i < needsRw.length; i++) {
    const doc   = needsRw[i]
    const docId = doc._id.toString()

    process.stdout.write(`\r   [${i + 1}/${needsRw.length}] ${doc.articleNumber.padEnd(15)} `)

    try {
      const rwText = await generateSimplifiedRw(doc)
      pendingSave.push({ id: docId, rw: rwText })
      done.add(docId)
      success++

      // Flush to DB every BATCH_DB articles
      if (pendingSave.length >= BATCH_DB || i === needsRw.length - 1) {
        const ops = pendingSave.map(({ id, rw }) => ({
          updateOne: {
            filter: { _id: new mongoose.Types.ObjectId(id) },
            update: { $set: { 'simplifiedExplanation.rw': rw } }
          }
        }))
        await LegalContent.bulkWrite(ops, { ordered: false })
        saveCheckpoint([...done])
        pendingSave.length = 0
        process.stdout.write('💾')
      }

      // Rate limit delay
      if (i < needsRw.length - 1) {
        await new Promise(r => setTimeout(r, DELAY_MS))
      }

    } catch (err) {
      failed++
      process.stdout.write(`❌ ${err.message?.substring(0, 40)}`)
      // On rate limit error, wait longer
      if (err.status === 429) {
        console.log('\n   ⏳  Rate limited — waiting 65 seconds...')
        await new Promise(r => setTimeout(r, 65000))
      }
    }
  }

  console.log('\n')

  // ── Final summary ─────────────────────────────────────────────────────────
  const finalMissing = await LegalContent.countDocuments({
    'simplifiedExplanation.rw': { $in: ['', null] }
  })

  console.log('✅  Backfill complete!')
  console.log(`   Groq generated : ${success}`)
  console.log(`   Failed          : ${failed}`)
  console.log(`   Still missing   : ${finalMissing}`)

  if (finalMissing === 0) {
    // Clean up checkpoint — all done
    if (existsSync(CHECKPOINT_FILE)) {
      writeFileSync(CHECKPOINT_FILE, JSON.stringify({ completed: [], finished: true }, null, 2))
    }
    console.log('   🎉  All articles fully bilingual!')
  } else {
    console.log(`   ▶️   Run again to complete the remaining ${finalMissing} articles.`)
  }
}

backfill()
  .catch(err => {
    console.error('\n❌  Fatal error:', err.message)
    process.exit(1)
  })
  .finally(() => mongoose.disconnect())
